// Auto-generated: official USNH campus logos embedded as data so the tool is fully self-contained.
window.LOGOS = {
  ksc: { type: "img", src: "data:image/png;base64," },
  psu: { type: "img", src: "data:image/png;base64," },
  unh: { type: "svg", b64: "" }
};

/* ------------------------------------------------------------------
   Logo helper shared by the makers.
   getLogoNode(key, {white}) -> Promise<htmlString>
     - returns inline <svg> (for svg logos) or <img> (for png logos)
     - white:true recolors the mark to solid white so it reads on a
       dark or brand-colored chip (KSC/PSU via canvas, UNH via fill swap)
   ------------------------------------------------------------------ */
window.CAMPUS_COLORS = { ksc:'#C8102E', psu:'#00573F', unh:'#003591' };

window.getLogoNode = function(key, opts){
  opts = opts || {};
  var white = !!opts.white;
  return new Promise(function(resolve){
    var L = (window.LOGOS || {})[key];
    if(!L){ resolve(''); return; }

    if(L.type === 'svg'){
      var svg = decodeURIComponent(escape(atob(L.b64)));
      if(white){ svg = svg.replace(/fill:#[0-9a-fA-F]{3,6}/g, 'fill:#ffffff'); }
      resolve(svg);
      return;
    }

    if(L.type === 'img'){
      if(!white){ resolve('<img alt="" src="' + L.src + '">'); return; }
      var img = new Image();
      img.onload = function(){
        var w = img.naturalWidth || img.width, h = img.naturalHeight || img.height;
        var cv = document.createElement('canvas'); cv.width = w; cv.height = h;
        var ctx = cv.getContext('2d');
        ctx.drawImage(img, 0, 0, w, h);
        try{
          var d = ctx.getImageData(0, 0, w, h), a = d.data;
          for(var i = 0; i < a.length; i += 4){ a[i] = 255; a[i+1] = 255; a[i+2] = 255; }
          ctx.putImageData(d, 0, 0);
          resolve('<img alt="" src="' + cv.toDataURL('image/png') + '">');
        }catch(e){ resolve('<img alt="" src="' + L.src + '">'); }
      };
      img.onerror = function(){ resolve('<img alt="" src="' + L.src + '">'); };
      img.src = L.src;
    }
  });
};
